389→    private fun onFollowSiteClicked(recommendedBlogUiState: ReaderRecommendedBlogUiState) {
390→        launch {
391→            readerTracker.trackBlog(
392→                AnalyticsTracker.Stat.READER_SUGGESTED_SITE_TOGGLE_FOLLOW,
393→                recommendedBlogUiState.blogId,
394→                recommendedBlogUiState.feedId,
395→                !recommendedBlogUiState.isFollowed
396→            )
397→            readerPostCardActionsHandler.handleFollowRecommendedSiteClicked(
398→                recommendedBlogUiState,
399→                ReaderTracker.SOURCE_DISCOVER
400→            )
401→        }
402→    }
