 51→/**
 52→ * This class contains logic related to fetching data for the discover tab in the Reader.
 53→ */
 54→class ReaderDiscoverLogic @Inject constructor(
 55→    private val parseDiscoverCardsJsonUseCase: ParseDiscoverCardsJsonUseCase,
 56→    private val readerTagTableWrapper: ReaderTagTableWrapper,
 57→    private val getFollowedTagsUseCase: GetFollowedTagsUseCase,
 58→    private val getDiscoverCardsUseCase: GetDiscoverCardsUseCase,
 59→    private val appPrefsWrapper: AppPrefsWrapper,
 60→) {
 61→    enum class DiscoverTasks {
 62→        REQUEST_MORE, REQUEST_FIRST_PAGE
 63→    }
 64→
 65→    private var listenerCompanion: JobParameters? = null
 66→    private var coroutineScope: CoroutineScope? = null
 67→
 68→    fun performTasks(
 69→        task: DiscoverTasks,
 70→        companion: JobParameters?,
 71→        scope: CoroutineScope,
 72→        completionListener: ServiceCompletionListener
 73→    ) {
 74→        listenerCompanion = companion
 75→        coroutineScope = scope
 76→        requestDataForDiscover(task) {
 77→            EventBus.getDefault().post(FetchDiscoverCardsEnded(task, it))
 78→            completionListener.onCompleted(listenerCompanion)
 79→        }
 80→    }
 81→
 82→    private fun requestDataForDiscover(taskType: DiscoverTasks, resultListener: UpdateResultListener) {
 83→        coroutineScope?.launch {
 84→            val params = HashMap<String, String>()
 85→            params["tags"] = getFollowedTagsUseCase.get().joinToString { it.tagSlug }
 86→            params["tag_recs_per_card"] = RECOMMENDED_TAGS_COUNT
 87→
 88→            when (taskType) {
 89→                REQUEST_FIRST_PAGE -> {
 90→                    appPrefsWrapper.readerCardsPageHandle = null
 91→                    /* "refresh" parameter is used to tell the server to return a different set of data so we don't
 92→                    present a static content to the user. We need to include it only for the first page (when
 93→                    page_handle is empty). The server will take care of including the "refresh" parameter within the
 94→                    page_handle so the user will stay on the same shard while they’re paging through the cards. */
 95→                    params["refresh"] = appPrefsWrapper.getReaderCardsRefreshCounter().toString()
 96→                    appPrefsWrapper.incrementReaderCardsRefreshCounter()
 97→                }
 98→                REQUEST_MORE -> {
 99→                    val pageHandle = appPrefsWrapper.readerCardsPageHandle
100→                    if (pageHandle?.isNotEmpty() == true) {
101→                        params["page_handle"] = pageHandle
102→                    } else {
103→                        // there are no more pages to load
104→                        resultListener.onUpdateResult(UNCHANGED)
105→                        return@launch
106→                    }
107→                }
108→            }
109→
110→            val listener = Listener { jsonObject ->
111→                coroutineScope?.launch {
112→                    handleRequestDiscoverDataResponse(taskType, jsonObject, resultListener)
113→                }
114→            }
115→            val errorListener = ErrorListener { volleyError ->
116→                AppLog.e(READER, volleyError)
117→                resultListener.onUpdateResult(FAILED)
118→            }
119→            WordPress.getRestClientUtilsV2()["read/tags/cards", params, null, listener, errorListener]
120→        }
121→    }
122→
123→    private suspend fun handleRequestDiscoverDataResponse(
124→        taskType: DiscoverTasks,
125→        json: JSONObject?,
126→        resultListener: UpdateResultListener
127→    ) {
128→        if (json == null) {
129→            resultListener.onUpdateResult(FAILED)
130→            return
131→        }
132→        if (taskType == REQUEST_FIRST_PAGE) {
133→            clearCache()
134→        }
135→        json.optJSONArray(JSON_CARDS)?.let { fullCardsJson ->
136→            // Parse the json into cards model objects
137→            val cards = parseCards(fullCardsJson)
138→            insertPostsIntoDb(cards.filterIsInstance<ReaderPostCard>().map { it.post })
139→            insertBlogsIntoDb(cards.filterIsInstance<ReaderRecommendedBlogsCard>().map { it.blogs }.flatten())
140→
141→            // Simplify the json. The simplified version is used in the upper layers to load the data from the db.
142→            val simplifiedCardsJson = createSimplifiedJson(fullCardsJson, taskType)
143→            insertCardsJsonIntoDb(simplifiedCardsJson)
144→
145→            val nextPageHandle = parseDiscoverCardsJsonUseCase.parseNextPageHandle(json)
146→            appPrefsWrapper.readerCardsPageHandle = nextPageHandle
147→
148→            if (cards.isEmpty()) {
149→                readerTagTableWrapper.clearTagLastUpdated(ReaderTag.createDiscoverPostCardsTag())
150→            } else {
151→                readerTagTableWrapper.setTagLastUpdated(ReaderTag.createDiscoverPostCardsTag())
152→            }
153→
154→            resultListener.onUpdateResult(HAS_NEW)
155→        }
156→    }
157→
158→    private fun parseCards(cardsJsonArray: JSONArray): ArrayList<ReaderDiscoverCard> {
159→        val cards: ArrayList<ReaderDiscoverCard> = arrayListOf()
160→        for (i in 0 until cardsJsonArray.length()) {
161→            val cardJson = cardsJsonArray.getJSONObject(i)
162→            when (cardJson.getString(JSON_CARD_TYPE)) {
163→                JSON_CARD_INTERESTS_YOU_MAY_LIKE -> {
164→                    val interests = parseDiscoverCardsJsonUseCase.parseInterestCard(cardJson)
165→                    cards.add(InterestsYouMayLikeCard(interests))
166→                }
167→                JSON_CARD_POST -> {
168→                    val post = parseDiscoverCardsJsonUseCase.parsePostCard(cardJson)
169→                    cards.add(ReaderPostCard(post))
170→                }
171→                JSON_CARD_RECOMMENDED_BLOGS -> {
172→                    cardJson?.let {
173→                        val recommendedBlogs = parseDiscoverCardsJsonUseCase.parseRecommendedBlogsCard(it)
174→                        cards.add(ReaderRecommendedBlogsCard(recommendedBlogs))
175→                    }
176→                }
177→            }
178→        }
179→        return cards
180→    }
181→
182→    private fun insertPostsIntoDb(posts: List<ReaderPost>) {
183→        val postList = ReaderPostList()
184→        postList.addAll(posts)
185→        ReaderPostTable.addOrUpdatePosts(ReaderTag.createDiscoverPostCardsTag(), postList)
186→    }
187→
188→    private fun insertBlogsIntoDb(blogs: List<ReaderBlog>) {
189→        blogs.forEach { blog ->
190→            ReaderBlogTable.addOrUpdateBlog(blog)
191→        }
192→    }
193→
194→    /**
195→     * This method creates a simplified version of the provided json.
196→     *
197→     * It for example copies only ids from post object as we don't need to store the gigantic post in the json
198→     * as it's already stored in the db.
199→     */
200→    @Suppress("NestedBlockDepth")
201→    private fun createSimplifiedJson(cardsJsonArray: JSONArray, discoverTasks: DiscoverTasks): JSONArray {
202→        var index = 0
203→        val simplifiedJson = JSONArray()
204→        for (i in 0 until cardsJsonArray.length()) {
205→            val cardJson = cardsJsonArray.getJSONObject(i)
206→            when (cardJson.getString(JSON_CARD_TYPE)) {
207→                JSON_CARD_RECOMMENDED_BLOGS -> {
208→                    cardJson.optJSONArray(JSON_CARD_DATA)?.let { recommendedBlogsCardJson ->
209→                        if (recommendedBlogsCardJson.length() > 0) {
210→                            simplifiedJson.put(index++, createSimplifiedRecommendedBlogsCardJson(cardJson))
211→                        }
212→                    }
213→                }
214→                JSON_CARD_INTERESTS_YOU_MAY_LIKE -> {
215→                    // We should not have an interests/tags card as the first element on Discover feed.
216→                    if (i == 0 && discoverTasks == REQUEST_FIRST_PAGE) {
217→                        continue
218→                    }
219→                    simplifiedJson.put(index++, cardJson)
220→                }
221→                JSON_CARD_POST -> {
222→                    simplifiedJson.put(index++, createSimplifiedPostJson(cardJson))
223→                }
224→            }
225→        }
226→        return simplifiedJson
227→    }
228→
229→    /**
230→     * Create a simplified copy of the json - keeps only postId, siteId and pseudoId.
231→     */
232→    private fun createSimplifiedPostJson(originalCardJson: JSONObject): JSONObject {
233→        val originalPostData = originalCardJson.getJSONObject(JSON_CARD_DATA)
234→
235→        val simplifiedPostData = JSONObject()
236→        // copy only fields which uniquely identify this post
237→        simplifiedPostData.put(POST_ID, originalPostData.get(POST_ID))
238→        simplifiedPostData.put(POST_SITE_ID, originalPostData.get(POST_SITE_ID))
239→        simplifiedPostData.put(POST_PSEUDO_ID, originalPostData.get(POST_PSEUDO_ID))
240→
241→        val simplifiedCardJson = JSONObject()
242→        simplifiedCardJson.put(JSON_CARD_TYPE, originalCardJson.getString(JSON_CARD_TYPE))
243→        simplifiedCardJson.put(JSON_CARD_DATA, simplifiedPostData)
244→        return simplifiedCardJson
245→    }
246→
247→    @Suppress("NestedBlockDepth")
248→    private fun createSimplifiedRecommendedBlogsCardJson(originalCardJson: JSONObject): JSONObject {
249→        return JSONObject().apply {
250→            JSONArray().apply {
251→                originalCardJson.optJSONArray(JSON_CARD_DATA)?.let { jsonRecommendedBlogs ->
252→                    for (i in 0 until jsonRecommendedBlogs.length()) {
253→                        JSONObject().apply {
254→                            val jsonRecommendedBlog = jsonRecommendedBlogs.getJSONObject(i)
255→                            put(RECOMMENDED_BLOG_ID, jsonRecommendedBlog.optLong(RECOMMENDED_BLOG_ID))
256→                            put(RECOMMENDED_FEED_ID, jsonRecommendedBlog.optLong(RECOMMENDED_FEED_ID))
257→                        }.let {
258→                            put(it)
259→                        }
260→                    }
261→                }
262→            }.let { simplifiedRecommendedBlogsJson ->
263→                put(JSON_CARD_TYPE, originalCardJson.getString(JSON_CARD_TYPE))
264→                put(JSON_CARD_DATA, simplifiedRecommendedBlogsJson)
265→            }
266→        }
267→    }
268→
269→    private fun insertCardsJsonIntoDb(simplifiedCardsJson: JSONArray) {
270→        ReaderDiscoverCardsTable.addCardsPage(simplifiedCardsJson.toString())
271→    }
272→
273→    private suspend fun clearCache() {
274→        val blogIds = getRecommendedBlogsToBeDeleted().map { it.blogId }
275→        ReaderBlogTable.deleteBlogsWithIds(blogIds)
276→
277→        ReaderDiscoverCardsTable.clear()
278→        ReaderPostTable.deletePostsWithTag(ReaderTag.createDiscoverPostCardsTag())
279→    }
280→
281→    private suspend fun getRecommendedBlogsToBeDeleted(): List<ReaderBlog> {
282→        val discoverCards = getDiscoverCardsUseCase.get()
283→
284→        val blogsToBeDeleted = ArrayList<ReaderBlog>()
285→        discoverCards.cards.filterIsInstance<ReaderRecommendedBlogsCard>().forEach {
286→            it.blogs.forEach { blog ->
287→                if (!blog.isFollowing) {
288→                    blogsToBeDeleted.add(blog)
289→                }
290→            }
291→        }
292→
293→        return blogsToBeDeleted
294→    }
295→
296→    companion object {
297→        private const val RECOMMENDED_TAGS_COUNT = "5"
298→    }
299→}
