    private fun hasUserSelectedTags(userTags: ReaderTagList): Boolean {
        return userTags.any { tag -> !isAutoFollowedTag(tag) }
    }

    private fun isAutoFollowedTag(tag: ReaderTag): Boolean {
        return tag.tagSlug.equals(BLOGGING_PROMPT_TAG, ignoreCase = true)
